37	error_t sign(job_mp_t& job, key_t& key, mem_t msg, const party_idx_t sig_receiver,
38	             const std::vector<std::vector<int>>& ot_role_map, buf_t& sig) {
39	  error_t rv = UNINITIALIZED_ERROR;
40	
41	  int peers_count = job.get_n_parties();
42	  int peer_index = job.get_party_idx();
43	  int i = peer_index;
44	  int n = peers_count;
45	
46	  // Validate ot_role_map dimensions and values up-front to avoid UB / OOB access via operator[].
47	  if ((int)ot_role_map.size() != n) return coinbase::error(E_BADARG, "invalid ot_role_map: row count mismatch");
48	  for (int r = 0; r < n; r++) {
49	    if ((int)ot_role_map[r].size() != n) return coinbase::error(E_BADARG, "invalid ot_role_map: column count mismatch");
50	  }
51	  for (int r = 0; r < n; r++) {
52	    for (int c = 0; c < n; c++) {
53	      int role = ot_role_map[r][c];
54	      if (r == c) {
55	        if (role != ot_no_role) return coinbase::error(E_BADARG, "invalid ot_role_map: diagonal must be ot_no_role");
56	        continue;
57	      }
58	      if (role != ot_sender && role != ot_receiver)
59	        return coinbase::error(E_BADARG, "invalid ot_role_map: entries must be ot_sender or ot_receiver");
60	      int opp = ot_role_map[c][r];
61	      if ((role == ot_sender && opp != ot_receiver) || (role == ot_receiver && opp != ot_sender))
62	        return coinbase::error(E_BADARG, "invalid ot_role_map: roles must be anti-symmetric");
63	    }
64	  }
65	
66	  auto sid_i = job.uniform_msg<buf_t>(crypto::gen_random_bitlen(SEC_P_COM));
67	
68	  ecurve_t curve = key.curve;
69	  const mod_t& q = curve.order();
70	  const auto& G = curve.generator();
71	  int theta = q.get_bits_count() + kappa;
72	
73	  if (key.x_share * G != key.Qis.at(job.get_name(i))) return coinbase::error(E_BADARG, "x_share does not match Qi");
74	  if (SUM(key.Qis) != key.Q) return coinbase::error(E_BADARG, "Q does not match the sum of Qis");
75	  auto h_consistency = job.uniform_msg<buf256_t>();
76	  h_consistency._i = crypto::sha256_t::hash(msg, key.Q, key.Qis);
77	
78	  // --------------------- Start of the 1st round of Pre-message section
79	
80	  // s_i and Ei are related to 1st round of the ec-dkg for ElGamal commitment key.
81	  bn_t s_i = bn_t::rand(q);
82	  auto Ei_gen = job.uniform_msg<ecc_point_t>(s_i * G);
83	  coinbase::crypto::commitment_t com(sid_i.msg, job.get_pid(i));
84	  com.gen(Ei_gen.msg, peer_index);
85	  auto c = job.uniform_msg<buf_t>(com.msg);
86	
87	  if (rv = job.plain_broadcast(sid_i, c, h_consistency)) return rv;
88	
89	  // ---------------------- Start of 2nd round of Pre-message section and first round of the signing protocol
90	  // ---------------------- and the 2nd round of DKG and completion of the input consistency check
91	
92	  for (int j = 0; j < n; j++) {
93	    if (j == i) continue;
94	    if (h_consistency._j != h_consistency) return coinbase::error(E_CRYPTO);
95	  }
96	
97	  // This is added to adhere to `GenerateSID-Dynamic-MP` api in the spec
98	  // This overlaps with the computation of sid for ec-dkg as well
99	  auto pids = job.get_pids();
100	  std::sort(pids.begin(), pids.end());
101	  buf_t sid = crypto::sha256_t::hash(sid_i._js, pids);
102	
103	  // This is for the 2nd round of dkg for the ElGamal commitment key
104	  auto h_gen = job.uniform_msg<buf256_t>(crypto::sha256_t::hash(c._js));
105	  auto rho = job.uniform_msg<buf256_t>(com.rand);
106	  auto pi_s = job.uniform_msg<zk::uc_dl_t>();
107	  pi_s.prove(Ei_gen, s_i, sid, peers_count + peer_index);
108	
109	  // Proceed with the signing protocol
110	  std::vector<mpc::ot_protocol_pvw_ctx_t> ot(n, mpc::ot_protocol_pvw_ctx_t(curve));
111	  std::vector<coinbase::bits_t> R_bits_i(n);
112	  std::vector<std::array<bool, 4>> R[theta];
113	  for (int l = 0; l < theta; l++) R[l].resize(n);
114	
115	  // This is step 5.(a): generating the pairwise sids for OTs
116	  for (int j = 0; j < n; j++) {
117	    int rid_s, rid_r;
118	    if (ot_role_map[i][j] == ot_sender) {
119	      rid_s = i;
120	      rid_r = j;
121	    } else {
122	      rid_s = j;
123	      rid_r = i;
124	    }
125	    ot[j].base.sid = crypto::sha256_t::hash(sid, rid_s, rid_r);
126	  }
127	
128	  for (int j = 0; j < n; j++) {
129	    if (ot_role_map[i][j] != ot_sender) continue;
130	    if (rv = ot[j].step1_S2R()) return rv;
131	  }
132	
133	  party_set_t ot_senders = ot_senders_for(i, n, ot_role_map);
134	  party_set_t ot_receivers = ot_receivers_for(i, n, ot_role_map);
135	
136	  auto ot_msg1 = job.inplace_msg<mpc::ot_protocol_pvw_ctx_t::msg1_t>([&ot](int j) -> auto { return ot[j].msg1(); });
137	  if (rv = plain_broadcast_and_pairwise_message(job, ot_receivers, ot_msg1, h_gen, Ei_gen, rho, pi_s)) return rv;
138	
139	  // ---------------------- Start of the 2nd round of the signing protocol
140	
141	  // Output generation from DKG for the ElGamal commitment key
142	  for (int j = 0; j < n; j++) {
143	    if (i == j) continue;
144	    if (h_gen._j != h_gen.msg) return coinbase::error(E_CRYPTO);
145	    if (rv = coinbase::crypto::commitment_t(sid_i._j, job.get_pid(j)).set(rho._j, c._j).open(Ei_gen._j, j)) return rv;
146	    // Verifying that Ei_gen values are valid is done in the following verification function
147	    if (rv = pi_s._j.verify(Ei_gen._j, sid, peers_count + j)) return rv;
148	  }
149	  const std::vector<ecc_point_t>& E_i = Ei_gen.all_received();
150	  ecc_point_t E = SUM(E_i);
151	
152	  // Proceed with the signing protocol
153	  for (int j = 0; j < n; j++) {
154	    if (ot_role_map[i][j] != ot_receiver) continue;
155	    R_bits_i[j] = crypto::gen_random_bits(4 * theta);
156	    for (int l = 0; l < theta; l++) {
157	      for (int t = 0; t < 4; t++) R[l][j][t] = R_bits_i[j][l * 4 + t];
158	    }
159	  }
160	
161	  for (int j = 0; j < n; j++) {
162	    if (ot_role_map[i][j] != ot_receiver) continue;
163	    if (rv = ot[j].step2_R2S(R_bits_i[j], q.get_bits_count())) return rv;
164	  }
165	
166	  auto ot_msg2 = job.inplace_msg<mpc::ot_protocol_pvw_ctx_t::msg2_t>([&ot](int j) -> auto { return ot[j].msg2(); });
167	  if (rv = plain_broadcast_and_pairwise_message(job, ot_senders, ot_msg2)) return rv;
168	
169	  // ---------------------- Start of the 3rd round of the signing protocol
170	  bn_t k_i = bn_t::rand(q);
171	  bn_t rho_i = bn_t::rand(q);
172	  bn_t r_eK_i = bn_t::rand(q);
173	  bn_t r_eRHO_i = bn_t::rand(q);
174	
175	  auto eK_i = job.uniform_msg<elg_com_t>(elg_com_t::commit(E, k_i).rand(r_eK_i));
176	  auto eRHO_i = job.uniform_msg<elg_com_t>(elg_com_t::commit(E, rho_i).rand(r_eRHO_i));
177	
178	  // The steps in Message 3 (continued)
179	  const int n_uc_elgamal_com_proofs = 4;
180	  auto pi_eK = job.uniform_msg<zk::uc_elgamal_com_t>();
181	  auto pi_eRHO = job.uniform_msg<zk::uc_elgamal_com_t>();
182	  pi_eK._i.prove(E, eK_i, k_i, r_eK_i, sid, n_uc_elgamal_com_proofs * i + 0);
183	  pi_eRHO._i.prove(E, eRHO_i, rho_i, r_eRHO_i, sid, n_uc_elgamal_com_proofs * i + 1);
184	
185	  bn_t x_i = key.x_share;
186	
187	  // The other steps related to OT
188	  std::vector<std::array<bn_t, 4>> delta[theta];
189	  for (int l = 0; l < theta; l++) delta[l].resize(n);
190	  for (int j = 0; j < n; j++) {
191	    if (ot_role_map[i][j] != ot_sender) continue;
192	
193	    bn_t a[] = {rho_i, k_i, rho_i, x_i};
194	
195	    std::vector<bn_t> D(4 * theta);
196	    bn_t Delta[4];
197	    for (int t = 0; t < 4; t++) MODULO(q) Delta[t] = a[t] + a[t];
198	
199	    for (int l = 0; l < theta; l++)
200	      for (int t = 0; t < 4; t++) D[l * 4 + t] = Delta[t];
201	
202	    std::vector<bn_t> X0, _X1;
203	    if (rv = ot[j].step3_S2R(D, q, X0, _X1)) return rv;
204	
205	    for (int l = 0; l < theta; l++)
206	      for (int t = 0; t < 4; t++) MODULO(q) delta[l][j][t] = X0[l * 4 + t] + a[t];
207	  }
208	
209	  auto ot_msg3 =
210	      job.inplace_msg<mpc::ot_protocol_pvw_ctx_t::msg3_delta_t>([&ot](int j) -> auto { return ot[j].msg3_delta(); });
211	  if (rv = plain_broadcast_and_pairwise_message(job, ot_receivers, ot_msg3, eK_i, eRHO_i, pi_eK, pi_eRHO)) return rv;
212	
213	  // ---------------------- Start of the 4th round of the signing protocol
214	
215	  // Generate OT output
216	  std::vector<std::array<bn_t, 4>> X[theta];
217	  for (int l = 0; l < theta; l++) X[l].resize(n);
218	  for (int j = 0; j < n; j++) {
219	    if (ot_role_map[i][j] != ot_receiver) continue;
220	
221	    std::vector<buf_t> X_bin;
222	    if (rv = ot[j].output_R(4 * theta, X_bin)) return rv;
223	
224	    for (int l = 0; l < theta; l++)
225	      for (int t = 0; t < 4; t++) X[l][j][t] = bn_t::from_bin(X_bin[l * 4 + t]);
226	  }
227	
228	  // Initialize the view
229	  crypto::sha256_t view;
230	  view.update(E_i, eK_i._js, eRHO_i._js, pi_eK._js, pi_eRHO._js);
231	
232	  // Proceed with message 4 of the signing protocol
233	  for (int j = 0; j < n; j++) {
234	    if (i == j) continue;
235	    // The check for validating eK_i and eRHO_i is done in the verify function
236	    if (rv = pi_eK._j.verify(E, eK_i._j, sid, n_uc_elgamal_com_proofs * j + 0)) return rv;
237	    if (rv = pi_eRHO._j.verify(E, eRHO_i._j, sid, n_uc_elgamal_com_proofs * j + 1)) return rv;
238	  }
239	
240	  auto seed = job.nonuniform_msg<buf256_t>();
241	  auto v_theta = job.nonuniform_msg<std::array<bn_t, 4>>();
242	
243	  std::vector<std::array<bn_t, 4>> s[2];
244	  s[ot_sender].resize(n);
245	  s[ot_receiver].resize(n);
246	
247	  for (int j = 0; j < n; j++) {
248	    if (ot_role_map[i][j] != ot_receiver) continue;
249	    crypto::gen_random(seed._ij);
250	    crypto::drbg_aes_ctr_t drbg(seed._ij);
251	
252	    bn_t a[] = {k_i, rho_i, x_i, rho_i};
253	
254	    std::array<bn_t, 4> v[theta];
255	    for (int t = 0; t < 4; t++) {
256	      for (int l = 0; l < theta - 1; l++) v[l][t] = drbg.gen_bn(q);
257	
258	      bn_t temp = 0;
259	      MODULO(q) {
260	        for (int l = 0; l < theta - 1; l++) {
261	          if (R[l][j][t])
262	            temp += v[l][t];
263	          else
264	            temp -= v[l][t];
265	        }
266	      }
267	      MODULO(q) v[theta - 1][t] = R[theta - 1][j][t] ? a[t] - temp : temp - a[t];
268	
269	      bn_t sigma = drbg.gen_bn(q);
270	      bn_t sum = 0;
271	      MODULO(q) {
272	        for (int l = 0; l < theta; l++) sum += v[l][t] * X[l][j][t];
273	        s[ot_receiver][j][t] = sigma + sum;
274	      }
275	    }
276	    v_theta._ij = v[theta - 1];
277	  }
278	
279	  auto ot_part = job_mp_t::tie_msgs(seed, v_theta);
280	  if (rv = plain_broadcast_and_pairwise_message(job, ot_senders, ot_part)) return rv;
281	
282	  // ---------------------- Start of the 5th round of the signing protocol
283	  for (int j = 0; j < n; j++) {
284	    if (ot_role_map[i][j] != ot_sender) continue;
285	
286	    bn_t a[4] = {k_i, rho_i, x_i, rho_i};
287	
288	    std::array<bn_t, 4> v[theta];
289	    for (int t = 0; t < 4; t++) {
290	      const bn_t& vt = v_theta._j[t];
291	      if (!q.is_in_range(vt)) return coinbase::error(E_CRYPTO, "invalid v_theta");
292	    }
293	    v[theta - 1] = v_theta._j;
294	    crypto::drbg_aes_ctr_t drbg(seed._j);
295	
296	    for (int t = 0; t < 4; t++) {
297	      for (int l = 0; l < theta - 1; l++) v[l][t] = drbg.gen_bn(q);
298	      bn_t sigma = drbg.gen_bn(q);
299	
300	      bn_t sum = 0;
301	      MODULO(q) {
302	        for (int l = 0; l < theta; l++) sum -= v[l][t] * delta[l][j][t];
303	        s[ot_sender][j][t] = sum - sigma;
304	      }
305	    }
306	  }
307	
308	  bn_t rho_k_i;
309	  bn_t rho_x_i;
310	  MODULO(q) {
311	    rho_k_i = rho_i * k_i + SUM<bn_t>(n, [=](bn_t& sum, int j) {
312	                if (i == j) return;
313	                int role = ot_role_map[i][j];
314	                sum += s[role][j][0] + s[role][j][1];
315	              });
316	    rho_x_i = rho_i * x_i + SUM<bn_t>(n, [=](bn_t& sum, int j) {
317	                if (i == j) return;
318	                int role = ot_role_map[i][j];
319	                sum += s[role][j][2] + s[role][j][3];
320	              });
321	  }
322	
323	  bn_t r_eRHO_K = bn_t::rand(q);
324	  bn_t r_eRHO_X = bn_t::rand(q);
325	
326	  auto eRHO_K = job.uniform_msg<elg_com_t>(elg_com_t::commit(E, rho_k_i).rand(r_eRHO_K));
327	  auto eRHO_X = job.uniform_msg<elg_com_t>(elg_com_t::commit(E, rho_x_i).rand(r_eRHO_X));
328	  auto pi_eRHO_K = job.uniform_msg<zk::uc_elgamal_com_t>();
329	  auto pi_eRHO_X = job.uniform_msg<zk::uc_elgamal_com_t>();
330	  pi_eRHO_K.prove(E, eRHO_K, rho_k_i, r_eRHO_K, sid, n_uc_elgamal_com_proofs * i + 2);
331	  pi_eRHO_X.prove(E, eRHO_X, rho_x_i, r_eRHO_X, sid, n_uc_elgamal_com_proofs * i + 3);
332	
333	  elg_com_t eK = SUM(eK_i._js);
334	  elg_com_t eX = elg_com_t(G, E + key.Q);
335	
336	  bn_t r_F_eRHO_K = bn_t::rand(q);
337	  bn_t r_F_eRHO_X = bn_t::rand(q);
338	  auto F_eRHO_K = job.uniform_msg<elg_com_t>(elg_com_t::rerand(E, rho_i * eK).rand(r_F_eRHO_K));
339	  auto F_eRHO_X = job.uniform_msg<elg_com_t>(elg_com_t::rerand(E, rho_i * eX).rand(r_F_eRHO_X));
340	
341	  int n_elgamal_com_mult_proofs = 2;
342	  auto pi_F_eRHO_K = job.uniform_msg<zk::elgamal_com_mult_t>();
343	  auto pi_F_eRHO_X = job.uniform_msg<zk::elgamal_com_mult_t>();
344	  pi_F_eRHO_K.prove(E, eK, eRHO_i, F_eRHO_K, r_eRHO_i, r_F_eRHO_K, rho_i, sid, n_elgamal_com_mult_proofs * i + 0);
345	  pi_F_eRHO_X.prove(E, eX, eRHO_i, F_eRHO_X, r_eRHO_i, r_F_eRHO_X, rho_i, sid, n_elgamal_com_mult_proofs * i + 1);
346	
347	  if (rv = job.plain_broadcast(eRHO_K, pi_eRHO_K, eRHO_X, pi_eRHO_X, F_eRHO_K, pi_F_eRHO_K, F_eRHO_X, pi_F_eRHO_X))
348	    return rv;
349	
350	  // ---------------------- Start of the 6th round of the signing protocol
351	  view.update(eRHO_K._js, pi_eRHO_K._js, eRHO_X._js, pi_eRHO_X._js, F_eRHO_K._js, pi_F_eRHO_K._js, F_eRHO_X._js,
352	              pi_F_eRHO_X._js);
353	  auto h = job.uniform_msg<buf256_t>(view.final());
354	
355	  for (int j = 0; j < n; j++) {
356	    if (i == j) continue;
357	    // Curve checks are done inside the verify function
358	    if (rv = pi_F_eRHO_K._j.verify(E, eK, eRHO_i._j, F_eRHO_K._j, sid, n_elgamal_com_mult_proofs * j + 0)) return rv;
359	    if (rv = pi_F_eRHO_X._j.verify(E, eX, eRHO_i._j, F_eRHO_X._j, sid, n_elgamal_com_mult_proofs * j + 1)) return rv;
360	    if (rv = pi_eRHO_K._j.verify(E, eRHO_K._j, sid, n_uc_elgamal_com_proofs * j + 2)) return rv;
361	    if (rv = pi_eRHO_X._j.verify(E, eRHO_X._j, sid, n_uc_elgamal_com_proofs * j + 3)) return rv;
362	  }
363	
364	  elg_com_t Y_eRHO_K = SUM(F_eRHO_K._js) - SUM(eRHO_K._js);
365	  elg_com_t Y_eRHO_X = SUM(F_eRHO_X._js) - SUM(eRHO_X._js);
366	
367	  bn_t r_Z_eRHO_K = bn_t::rand(q);
368	  bn_t r_Z_eRHO_X = bn_t::rand(q);
369	  bn_t o_Z_eRHO_K = bn_t::rand(q);
370	  bn_t o_Z_eRHO_X = bn_t::rand(q);
371	
372	  auto Z_eRHO_K_i = job.uniform_msg<elg_com_t>(elg_com_t::rerand(E, o_Z_eRHO_K * Y_eRHO_K).rand(r_Z_eRHO_K));
373	  auto Z_eRHO_X_i = job.uniform_msg<elg_com_t>(elg_com_t::rerand(E, o_Z_eRHO_X * Y_eRHO_X).rand(r_Z_eRHO_X));
374	
375	  int n_elgamal_mult_private_scalar_proofs = 2;
376	  auto pi_Z_eRHO_K = job.uniform_msg<zk::uc_elgamal_com_mult_private_scalar_t>();
377	  auto pi_Z_eRHO_X = job.uniform_msg<zk::uc_elgamal_com_mult_private_scalar_t>();
378	  pi_Z_eRHO_K.prove(E, Y_eRHO_K, Z_eRHO_K_i, r_Z_eRHO_K, o_Z_eRHO_K, sid, n_elgamal_mult_private_scalar_proofs * i + 0);
379	  pi_Z_eRHO_X.prove(E, Y_eRHO_X, Z_eRHO_X_i, r_Z_eRHO_X, o_Z_eRHO_X, sid, n_elgamal_mult_private_scalar_proofs * i + 1);
380	
381	  if (rv = job.plain_broadcast(h, Z_eRHO_K_i, pi_Z_eRHO_K, Z_eRHO_X_i, pi_Z_eRHO_X)) return rv;
382	
383	  // ---------------------- Start of the 7th round of the signing protocol
384	  for (int j = 0; j < n; j++) {
385	    if (i == j) continue;
386	    if (h != h._j) return coinbase::error(E_CRYPTO);
387	
388	    if (rv = pi_Z_eRHO_K._j.verify(E, Y_eRHO_K, Z_eRHO_K_i._j, sid, n_elgamal_mult_private_scalar_proofs * j + 0))
389	      return rv;
390	    if (rv = pi_Z_eRHO_X._j.verify(E, Y_eRHO_X, Z_eRHO_X_i._j, sid, n_elgamal_mult_private_scalar_proofs * j + 1))
391	      return rv;
392	  }
393	
394	  auto h2 = job.uniform_msg<buf256_t>(
395	      crypto::sha256_t::hash(Z_eRHO_K_i._js, pi_Z_eRHO_K._js, Z_eRHO_X_i._js, pi_Z_eRHO_X._js, h.msg));
396	
397	  elg_com_t Z_eRHO_K = SUM(Z_eRHO_K_i._js);
398	  elg_com_t Z_eRHO_X = SUM(Z_eRHO_X_i._js);
399	
400	  auto W_eRHO_K_i = job.uniform_msg<ecc_point_t>(s_i * Z_eRHO_K.L);
401	  auto W_eRHO_X_i = job.uniform_msg<ecc_point_t>(s_i * Z_eRHO_X.L);
402	  int n_dh_proofs = 2;
403	  auto pi_W_eRHO_K = job.uniform_msg<zk::dh_t>();
404	  auto pi_W_eRHO_X = job.uniform_msg<zk::dh_t>();
405	  pi_W_eRHO_K.prove(Z_eRHO_K.L, E_i[i], W_eRHO_K_i, s_i, sid, n_dh_proofs * i + 0);
406	  pi_W_eRHO_X.prove(Z_eRHO_X.L, E_i[i], W_eRHO_X_i, s_i, sid, n_dh_proofs * i + 1);
407	
408	  auto K_i = job.uniform_msg<ecc_point_t>(k_i * G);
409	  int n_elgamal_com_pub_share_equ_proofs = 3;
410	  auto pi_K = job.uniform_msg<zk::elgamal_com_pub_share_equ_t>();
411	  pi_K.prove(E, K_i, eK_i, r_eK_i, sid, n_elgamal_com_pub_share_equ_proofs * i + 0);
412	
413	  if (rv = job.plain_broadcast(W_eRHO_K_i, pi_W_eRHO_K, W_eRHO_X_i, pi_W_eRHO_X, K_i, pi_K, h2)) return rv;
414	
415	  // ---------------------- Start of the 8th round of the signing protocol
416	  for (int j = 0; j < n; j++) {
417	    if (i == j) continue;
418	    if (h2 != h2._j) return coinbase::error(E_CRYPTO);
419	    if (rv = pi_W_eRHO_K._j.verify(Z_eRHO_K.L, E_i[j], W_eRHO_K_i._j, sid, n_dh_proofs * j + 0)) return rv;
420	    if (rv = pi_W_eRHO_X._j.verify(Z_eRHO_X.L, E_i[j], W_eRHO_X_i._j, sid, n_dh_proofs * j + 1)) return rv;
421	    if (rv = pi_K._j.verify(E, K_i._j, eK_i._j, sid, n_elgamal_com_pub_share_equ_proofs * j + 0)) return rv;
422	  }
423	
424	  ecc_point_t K = SUM(K_i._js);
425	  bn_t r_tag = K.get_x();
426	  bn_t r = r_tag % q;
427	
428	  ecc_point_t W_eRHO_K = SUM(W_eRHO_K_i._js);
429	  ecc_point_t W_eRHO_X = SUM(W_eRHO_X_i._js);
430	
431	  if (W_eRHO_K != Z_eRHO_K.R) return coinbase::error(E_CRYPTO);
432	  if (W_eRHO_X != Z_eRHO_X.R) return coinbase::error(E_CRYPTO);
433	
434	  bn_t m = curve_msg_to_bn(msg, curve);
435	  bn_t r_rho_x, rho_m, r_eR_RHO_X, r_eR_RHO_M, r_eB;
436	  auto beta = job.uniform_msg<bn_t>();
437	  MODULO(q) {
438	    r_rho_x = r * rho_x_i;
439	    rho_m = m * rho_i;
440	    beta.msg = r_rho_x + rho_m;
441	    r_eR_RHO_X = r * r_eRHO_X;
442	    r_eR_RHO_M = m * r_eRHO_i;
443	    r_eB = r_eR_RHO_X + r_eR_RHO_M;
444	  }
445	
446	  std::vector<elg_com_t> eB(n);
447	  for (int j = 0; j < n; j++) {
448	    elg_com_t eR_RHO_X = r * eRHO_X._j;
449	    elg_com_t eRHO_M = m * eRHO_i._j;
450	    eB[j] = eR_RHO_X + eRHO_M;
451	  }
452	  ecc_point_t RHO_K = rho_k_i * G;
453	  ecc_point_t B = beta * G;
454	  auto pi_R_eRHO_K = job.uniform_msg<zk::elgamal_com_pub_share_equ_t>();
455	  auto pi_R_eB = job.uniform_msg<zk::elgamal_com_pub_share_equ_t>();
456	  pi_R_eRHO_K.prove(E, RHO_K, eRHO_K, r_eRHO_K, sid, n_elgamal_com_pub_share_equ_proofs * i + 1);
457	  pi_R_eB.prove(E, B, eB[i], r_eB, sid, n_elgamal_com_pub_share_equ_proofs * i + 2);
458	
459	  auto rho_k = job.uniform_msg<bn_t>(rho_k_i);
460	
461	  if (rv = job.send_message_all_to_one(sig_receiver, rho_k, pi_R_eRHO_K, beta, pi_R_eB)) return rv;
462	
463	  // ---------------------- Start of output generation
464	  if (job.is_party_idx(sig_receiver)) {
465	    for (int j = 0; j < n; j++) {
466	      if (i == j) continue;
467	      ecc_point_t RHO_K = rho_k._j * G;
468	      ecc_point_t B = beta._j * G;
469	      if (rv = pi_R_eRHO_K._j.verify(E, RHO_K, eRHO_K._j, sid, n_elgamal_com_pub_share_equ_proofs * j + 1)) return rv;
470	      if (rv = pi_R_eB._j.verify(E, B, eB[j], sid, n_elgamal_com_pub_share_equ_proofs * j + 2)) return rv;
471	    }
472	
473	    bn_t sum_rho_k = SUM(rho_k._js, q);
474	    bn_t sum_beta = SUM(beta._js, q);
475	    bn_t s;
476	    MODULO(q) s = sum_beta / sum_rho_k;
477	
478	    bn_t s_reduced = q - s;
479	    if (s_reduced < s) s = s_reduced;
480	    sig = crypto::ecdsa_signature_t(curve, r, s).to_der();
481	    crypto::ecc_pub_key_t pub(key.Q);
482	    if (rv = pub.verify(msg, sig)) return rv;
483	  }
484	
485	  return SUCCESS;
486	}
487	
488	error_t sign(job_mp_t& job, key_t& key, mem_t msg, const party_idx_t sig_receiver, buf_t& sig) {
489	  int n = job.get_n_parties();
490	  std::vector<std::vector<int>> ot_role_map(n, std::vector<int>(n));
491	  for (int i = 0; i < n; i++) {
492	    ot_role_map[i][i] = ot_no_role;
493	  }
494	
495	  for (int i = 0; i <= n - 1; i++) {
496	    for (int j = i + 1; j < n; j++) {
497	      ot_role_map[i][j] = ot_sender;
498	      ot_role_map[j][i] = ot_receiver;
499	    }
500	  }
501	  return sign(job, key, msg, sig_receiver, ot_role_map, sig);
502	}
