18	void dkg_2p_t::step1_p1_to_p2(const bn_t& x1) {
19	  this->x1 = x1;
20	  const auto& G = curve.generator();
21	  sid1 = crypto::gen_random_bitlen(SEC_P_COM);
22	  Q1 = x1 * G;
23	
24	  com.id(sid1, p1_pid).gen(Q1);
25	}
26	
27	void dkg_2p_t::step2_p2_to_p1(const bn_t& x2) {
28	  this->x2 = x2;
29	  const auto& G = curve.generator();
30	  sid2 = crypto::gen_random_bitlen(SEC_P_COM);
31	  sid = crypto::sha256_t::hash(sid1, sid2);
32	
33	  Q2 = x2 * G;
34	  pi_2.prove(Q2, x2, sid, 2);
35	}
36	
37	error_t dkg_2p_t::step3_p1_to_p2(ecc_point_t& Q) {
38	  error_t rv = UNINITIALIZED_ERROR;
39	  if (rv = curve.check(Q2)) return coinbase::error(E_CRYPTO, "dkg_2p_t::p1_verify: check Q2 failed");
40	  sid = crypto::sha256_t::hash(sid1, sid2);
41	  if (rv = pi_2.verify(Q2, sid, 2)) return rv;
42	  pi_1.prove(Q1, x1, sid, 1);
43	  Q = Q1 + Q2;
44	  return SUCCESS;
45	}
46	
47	error_t dkg_2p_t::step4_output_p2(ecc_point_t& Q) {
48	  error_t rv = UNINITIALIZED_ERROR;
49	  if (rv = curve.check(Q1)) return coinbase::error(E_CRYPTO, "dkg_2p_t::p2_verify: check Q1 failed");
50	  if (rv = com.id(sid1, p1_pid).open(Q1)) return rv;
51	  if (rv = pi_1.verify(Q1, sid, 1)) return rv;
52	  Q = Q1 + Q2;
53	  return SUCCESS;
54	}
