56	error_t key_share_2p_t::dkg(job_2p_t& job, ecurve_t curve, key_share_2p_t& key, buf_t& sid) {
57	  error_t rv = UNINITIALIZED_ERROR;
58	  key.curve = curve;
59	  const mod_t& q = curve.order();
60	  eckey::dkg_2p_t ec_dkg(curve, job.get_pid(party_t::p1));
61	  key.x_share = bn_t::rand(q);
62	  key.role = job.get_party();
63	
64	  if (job.is_p1()) {
65	    ec_dkg.step1_p1_to_p2(key.x_share);
66	  }
67	
68	  if (rv = job.p1_to_p2(ec_dkg.msg1)) return rv;
69	
70	  if (job.is_p2()) {
71	    ec_dkg.step2_p2_to_p1(key.x_share);
72	  }
73	
74	  if (rv = job.p2_to_p1(ec_dkg.msg2)) return rv;
75	
76	  if (job.is_p1()) {
77	    if (rv = ec_dkg.step3_p1_to_p2(key.Q)) return rv;
78	  }
79	
80	  if (rv = job.p1_to_p2(ec_dkg.msg3)) return rv;
81	
82	  if (job.is_p2()) {
83	    if (rv = ec_dkg.step4_output_p2(key.Q)) return rv;
84	  }
85	
86	  sid = std::move(ec_dkg.sid);
87	  return SUCCESS;
88	}
