264	error_t key_share_mp_t::dkg_or_refresh_ac(job_mp_t& job, const ecurve_t& curve, buf_t& sid, const crypto::ss::ac_t ac,
265	                                          const party_set_t& quorum_party_set, key_share_mp_t& key,
266	                                          key_share_mp_t& new_key, bool is_refresh) {
267	  error_t rv = UNINITIALIZED_ERROR;
268	
269	  const auto& G = curve.generator();
270	  const mod_t& q = curve.order();
271	
272	  if (rv = ac.validate_tree()) {
273	    return coinbase::error(rv, "Invalid access structure");
274	  }
275	
276	  int n = job.get_n_parties();
277	  int quorum_count = 0;
278	  int i = job.get_party_idx();
279	  std::vector<crypto::mpc_pid_t> all_pids(n);
280	  std::map<party_idx_t, crypto::mpc_pid_t> quorum_pids;
281	  int representative_quorum_pid_index = -1;
282	  std::set<crypto::pname_t> quorum_pname_set;
283	  for (int j = 0; j < n; j++) {
284	    all_pids[j] = job.get_pid(j);
285	    if (quorum_party_set.has(j)) {
286	      quorum_pids[j] = job.get_pid(j);
287	      quorum_pname_set.insert(job.get_name(j));
288	      quorum_count++;
289	      representative_quorum_pid_index = j;
290	    }
291	  }
292	
293	  if (!ac.enough_for_quorum(quorum_pname_set)) {
294	    return coinbase::error(E_BADARG, "Not enough quorum parties");
295	  }
296	
297	  if (sid.empty()) {
298	    if (rv = coinbase::mpc::generate_sid_fixed_mp(job, sid)) return coinbase::error(rv, "Failed to generate sid");
299	  }
300	
301	  auto h_consistency = job.uniform_msg<buf256_t>();
302	  h_consistency._i = crypto::sha256_t::hash(std::string(curve.get_name()), all_pids, quorum_pids, sid);
303	
304	  if (rv = job.plain_broadcast(h_consistency)) return coinbase::error(rv, "Failed to broadcast h_consistency");
305	
306	  for (int j = 0; j < n; j++) {
307	    if (j == i) continue;
308	    if (h_consistency._j != h_consistency) return coinbase::error(E_CRYPTO, "h_consistency mismatch");
309	  }
310	
311	  auto xij = job.nonuniform_msg<bn_t>();
312	
313	  auto ac_pub_all = job.uniform_msg<ac_internal_pub_shares_t>();
314	  auto pi_r_all = job.uniform_msg<zk::uc_batch_dl_t>();
315	  auto c_all = job.uniform_msg<buf_t>();
316	  auto rho_all = job.uniform_msg<buf256_t>();
317	
318	  crypto::commitment_t com_R(job.get_pid(i));
319	
320	  if (quorum_party_set.has(i)) {
321	    std::vector<bn_t> rs;
322	    std::vector<ecc_point_t> Rs;
323	    bn_t r = 0;
324	    if (!is_refresh) {
325	      r = bn_t::rand(q);
326	    }
327	
328	    ac_internal_shares_t ac_internal_shares;
329	    ac_shares_t shares;
330	    if (rv = ac.share_with_internals(q, r, shares, ac_internal_shares, ac_pub_all._i))
331	      return coinbase::error(rv, "Failed to share with internals");
332	    for (int j = 0; j < n; j++) {
333	      xij.msgs[j] = shares[job.get_name(j)];
334	    }
335	
336	    if (is_refresh) {
337	      // Since the root is the point at infinity
338	      ac_pub_all._i.erase(ac.root->name);
339	    }
340	
341	    for (const auto& [node_name, internal_pub_shares] : ac_pub_all._i) {
342	      auto internal_share = ac_internal_shares.at(node_name);
343	      // NOTE: because of the less optimized implementation of the sharing, there are essentially duplicate data
344	      //       in `rs` and similarly in `Rs` which will cause us do more batch zk dl operations than necessary.
345	      rs.push_back(internal_share);
346	      Rs.push_back(internal_pub_shares);
347	    }
348	
349	    pi_r_all._i = zk::uc_batch_dl_t();
350	    pi_r_all._i.prove(Rs, rs, sid, i);
351	
352	    com_R.gen(Rs, pi_r_all._i);
353	    c_all._i = com_R.msg;
354	    rho_all._i = com_R.rand;
355	  }
356	
357	  if (rv = job.plain_broadcast(c_all)) return coinbase::error(rv, "Failed to broadcast c_all");
358	
359	  auto h_all = job.uniform_msg<buf256_t>();
360	  std::map<party_idx_t, buf_t> all_received_c_s;
361	  for (int j = 0; j < n; j++) {
362	    if (!quorum_party_set.has(j)) continue;
363	
364	    all_received_c_s[j] = c_all._j;
365	  }
366	  h_all._i = crypto::sha256_t::hash(all_received_c_s, quorum_pids, sid);
367	
368	  if (rv = job.plain_broadcast(h_all, ac_pub_all, pi_r_all, rho_all, xij))
369	    return coinbase::error(rv, "Failed to broadcast h_all, ac_pub_all, pi_r_all, rho_all, xij");
370	
371	  std::map<party_idx_t, buf_t> cs;
372	  for (int j = 0; j < n; j++) {
373	    if (j == i) continue;
374	    if (!quorum_party_set.has(j)) continue;
375	
376	    if (h_all._j != h_all.received(representative_quorum_pid_index)) return coinbase::error(E_CRYPTO, "h_all mismatch");
377	
378	    crypto::commitment_t com_R_tag(quorum_pids[j]);
379	    // deviation from the spec: since we are sending `c` to all parties, we open them for all parties.
380	    // furthermore, later on we compute the hash and check if the hash with the cs is correct.
381	    std::vector<ecc_point_t> Rs;
382	    for (const auto& [node_name, internal_pub_shares] : ac_pub_all._j) {
383	      Rs.push_back(internal_pub_shares);
384	    }
385	    com_R_tag.set(rho_all._j, c_all._j);
386	    if (rv = com_R_tag.open(Rs, pi_r_all._j)) return coinbase::error(rv, "Failed to open com_R_tag");
387	
388	    cs[j] = c_all._j;
389	    // Verifying that R values are on the curve and subgroup is done in the zk verify function
390	    if (rv = pi_r_all._j.verify(Rs, sid, j)) return coinbase::error(rv, "Failed to verify pi_r_all");
391	    if (is_refresh) {
392	      ac_pub_all._j[ac.root->name] = curve.infinity();
393	    }
394	    ecc_point_t Qj = ac_pub_all._j.at(ac.root->name);
395	    if (rv = ac.verify_share_against_ancestors_pub_data(Qj, xij._j, ac_pub_all._j, job.get_name(i)))
396	      return coinbase::error(rv, "Failed to verify share against ancestors pub data");
397	  }
398	
399	  if (!quorum_party_set.has(i)) {
400	    if (h_all.received(representative_quorum_pid_index) != crypto::sha256_t::hash(cs, quorum_pids, sid))
401	      return coinbase::error(E_CRYPTO, "h_all mismatch");
402	  }
403	
404	  ecc_point_t Q = curve.infinity();
405	  bn_t x_i = 0;
406	  for (int j = 0; j < n; j++) {
407	    if (!quorum_party_set.has(j)) continue;
408	    if (!is_refresh) {
409	      crypto::vartime_scope_t vartime_scope;
410	      Q += ac_pub_all._j.at(ac.root->name);
411	    }
412	    MODULO(q) x_i += xij._j;
413	  }
414	  ac_pub_shares_t Qis;
415	  for (int l = 0; l < n; l++) {
416	    Qis[job.get_name(l)] = curve.infinity();
417	  }
418	  for (int j = 0; j < n; j++) {
419	    if (!quorum_party_set.has(j)) continue;
420	
421	    for (int l = 0; l < n; l++) {
422	      crypto::vartime_scope_t vartime_scope;
423	      Qis[job.get_name(l)] += ac_pub_all._j.at(job.get_name(l));
424	    }
425	  }
426	
427	  {
428	    crypto::vartime_scope_t vartime_scope;
429	    ecc_point_t reconstructed_Q;
430	    if (rv = ac.reconstruct_exponent(Qis, reconstructed_Q))
431	      return coinbase::error(rv, "Failed to reconstruct exponent");
432	    if (reconstructed_Q != Q) return coinbase::error(E_CRYPTO, "Q mismatch");
433	  }
434	  if (x_i * G != Qis[job.get_name(i)]) return coinbase::error(E_CRYPTO, "x_i * G != Qis[job.get_name(i)]");
435	
436	  if (is_refresh) {
437	    new_key = key;
438	
439	    MODULO(q) new_key.x_share += x_i;
440	    for (int j = 0; j < n; j++) {
441	      crypto::vartime_scope_t vartime_scope;
442	      new_key.Qis[job.get_name(j)] += Qis[job.get_name(j)];
443	    }
444	    ecc_point_t reconstructed_Q;
445	    if (rv = ac.reconstruct_exponent(new_key.Qis, reconstructed_Q))
446	      return coinbase::error(rv, "Failed to reconstruct exponent for new_key");
447	    if (reconstructed_Q != key.Q) return coinbase::error(E_CRYPTO, "key.Q mismatch");
448	    new_key.party_name = job.get_name(i);
449	  } else {
450	    key.x_share = x_i;
451	    key.Q = Q;
452	    for (int j = 0; j < n; j++) {
453	      key.Qis[job.get_name(j)] = Qis[job.get_name(j)];
454	    }
455	    key.curve = curve;
456	    key.party_name = job.get_name(i);
457	  }
458	
459	  return SUCCESS;
460	}
