3	#include <cbmpc/internal/crypto/ro.h>
4	
5	namespace coinbase::crypto {
6	
7	/**
8	 * @notes:
9	 * - Based on the conventions in the basic-primitives-spec, by default we assume that the
10	 *   library has access to good pid values (e.g., the actual public key of the committing party).
11	 *   Therefore, the main way of using the commitment
12	 *   is to call it with a pid value (e.g., commitment_t(pid) or commitment_t(pid, receiver_pid)).
13	 *   These calls will generate a local sid together with the pid.
14	 *
15	 * - The calls to commitment_t(sid, pid) or commitment_t(sid, pid, receiver_pid) are meant to be
16	 *   used in two cases
17	 *   1. If a local sid has already been generated, and we want to be more efficient by reusing it.
18	 *      In this case, it is important to make sure the same local sid is NOT reused in two
19	 *      different commitments.
20	 *   2. If a good pid and global sid are already available and they are both provided just to be
21	 *      safe.
22	 *   3. If a good global sid is already available but a good pid is not available. This should
23	 *      not happen given our assumption above and is only considered for the rare cases that it
24	 *      might be needed.
25	 *
26	 * - The receiver_pid is used in cases that we want to bind the commitment to a specific recipient.
27	 *   It is typically not used, but sometimes can be useful (e.g., in committed pairwise broadcast).
28	 *
29	 * - How to use:
30	 *   - If sid is not passed:
31	 *     - create the commitment:
32	 *       - com(pid) followed by com.gen(args...)
33	 *     - send the commitment hash and sid to the receiver:
34	 *       - mpc_broadcast(com.msg)
35	 *     - send the opening:
36	 *       - mpc_broadcast(com.rand)
37	 *     - verify (sometimes when sending a batch of commitments, you may need to set the
38	 *       randomness, local sid, etc as well)
39	 *   - If sid is passed:
40	 *     - In this case, com.local_sid is not used and the caller is responsible for making sure
41	 *       that both sides have the same sid.
42	 *   - Both of these options can be used using the `id` method by first defining the commitment
43	 *     instance and then calling `id` with the appropriate arguments.
44	 */
45	struct commitment_t {
46	  buf256_t rand;
47	  buf_t msg;
48	  static constexpr size_t HASH_SIZE = 32;
49	  static constexpr size_t LOCAL_SID_SIZE = SEC_P_COM / 8;
50	
51	  explicit commitment_t(const mpc_pid_t& pid) : pid(pid) {};
52	  explicit commitment_t(const mpc_pid_t& pid, const mpc_pid_t& receiver_pid) : pid(pid), receiver_pid(receiver_pid) {};
53	  explicit commitment_t(const mem_t sid, const mpc_pid_t& pid) : external_sid(sid), pid(pid) {};
54	  explicit commitment_t(const mem_t sid, const mpc_pid_t& pid, const mpc_pid_t& receiver_pid)
55	      : external_sid(sid), pid(pid), receiver_pid(receiver_pid) {};
56	  commitment_t() {}
57	
58	  /**
59	   * @specs:
60	   * - basic-primitives-spec | Com-1P
61	   */
62	  template <typename... ARGS>
63	  void gen(const ARGS&... args) {
64	    crypto::gen_random(rand);
65	    gen_with_set_rand(args...);
66	  }
67	
68	  template <typename... ARGS>
69	  void gen_with_set_rand(const ARGS&... args) {
70	    if (external_sid.size == 0) {
71	      local_sid = gen_random_bitlen(SEC_P_COM);
72	    }
73	
74	    ro::hmac_state_t state(rand);
75	    state.encode_and_update(args...);
76	    msg = final(state);
77	  }
78	
79	  template <typename... ARGS>
80	  error_t open(const ARGS&... args) {
81	    ro::hmac_state_t state(rand);
82	    state.encode_and_update(args...);
83	    if (external_sid.size == 0) {
84	      // Means that local_sid was used and therefore it should be extracted out of the hash parameter
85	      if (msg.size() != HASH_SIZE + LOCAL_SID_SIZE) return coinbase::error(E_FORMAT);
86	      local_sid = msg.skip(HASH_SIZE);
87	    } else {
88	      if (msg.size() != HASH_SIZE) return coinbase::error(E_FORMAT);
89	    }
90	    buf_t m = final(state);
91	    if (m != msg) return coinbase::error(E_CRYPTO);
92	    return SUCCESS;
93	  }
94	
95	  commitment_t& id(const mem_t _sid, const mpc_pid_t& _pid, const mpc_pid_t& _receiver_pid) {
96	    external_sid = _sid;
97	    pid = _pid;
98	    receiver_pid = _receiver_pid;
99	    return *this;
100	  }
101	  commitment_t& id(const mem_t _sid, const mpc_pid_t& _pid) {
102	    external_sid = _sid;
103	    pid = _pid;
104	    return *this;
105	  }
106	  commitment_t& id(const mpc_pid_t& _pid) {
107	    pid = _pid;
108	    return *this;
109	  }
110	
111	  commitment_t& set(buf256_t _rand, buf_t _msg) {
112	    rand = _rand;
113	    msg = _msg;
114	    return *this;
115	  }
