55	error_t uc_dl_t::verify(const ecc_point_t& Q, mem_t session_id, uint64_t aux) const {
56	  error_t rv = UNINITIALIZED_ERROR;
57	  crypto::vartime_scope_t vartime_scope;
58	  if (rv = params.check()) return rv;
59	  int rho = params.rho;
60	  if (int(A.size()) != rho) return coinbase::error(E_CRYPTO, "uc_dl_t::verify: A.size() != rho");
61	  if (int(e.size()) != rho) return coinbase::error(E_CRYPTO, "uc_dl_t::verify: e.size() != rho");
62	  if (int(z.size()) != rho) return coinbase::error(E_CRYPTO, "uc_dl_t::verify: z.size() != rho");
63	
64	  ecurve_t curve = Q.get_curve();
65	  const mod_t& q = curve.order();
66	  if (rv = curve.check(Q)) return coinbase::error(rv, "uc_dl_t::verify: Q is not on the curve");
67	  for (int i = 0; i < rho; i++) {
68	    if (rv = curve.check(A[i])) return coinbase::error(rv, "uc_dl_t::verify: A[i] is not on the curve");
69	  }
70	
71	  const auto& G = curve.generator();
72	  uint32_t b_mask = params.b_mask();
73	  buf_t common_hash = crypto::ro::hash_string(G, Q, A, session_id, aux).bitlen(2 * SEC_P_COM);
74	
75	  bn_t z_sum = 0;
76	  bn_t e_sum = 0;
77	  ecc_point_t A_sum = curve.infinity();
78	
79	  for (int i = 0; i < rho; i++) {
80	    if (rv = crypto::check_right_open_range(0, z[i], q)) return rv;
81	
82	    bn_t sigma = bn_t::rand_bitlen(SEC_P_STAT);
83	    MODULO(q) {
84	      z_sum += sigma * z[i];
85	      e_sum += sigma * bn_t(e[i]);
86	    }
87	    A_sum += sigma * A[i];
88	
89	    uint32_t h = hash32bit_for_zk_fischlin(common_hash, i, e[i], z[i]) & b_mask;
90	    if (h != 0) return coinbase::error(E_CRYPTO, "uc_dl_t::verify: zk_fischlin hash not equal zero");
91	  }
92	
93	  if (A_sum != z_sum * G - e_sum * Q) return coinbase::error(E_CRYPTO, "uc_dl_t::verify: A != z * G - e * Q");
94	  return SUCCESS;
95	}
