389	error_t sign_ac(const job_mp_t& job, mem_t ac_key_blob, const access_structure_t& access_structure, mem_t msg,
390	                party_idx_t sig_receiver, buf_t& sig_der) {
391	  error_t rv = validate_job_mp(job);
392	  if (rv) return rv;
