396	  if (rv = coinbase::api::detail::validate_mem_arg_max_size(msg, "msg", coinbase::api::detail::MAX_MESSAGE_DIGEST_SIZE))
397	    return rv;
398	  if (sig_receiver < 0 || static_cast<size_t>(sig_receiver) >= job.party_names.size())
399	    return coinbase::error(E_BADARG, "invalid sig_receiver");
400	
401	  coinbase::mpc::ecdsampc::key_t ac_key;
402	  rv = deserialize_ac_key_blob(ac_key_blob, ac_key);
403	  if (rv) return rv;
404	
405	  // Bind the key share to the local party identity in the job.
406	  const std::string_view self_name_sv(job.party_names[static_cast<size_t>(job.self)]);
407	  if (ac_key.party_name != self_name_sv) return coinbase::error(E_BADARG, "job.self mismatch key blob");
408	
409	  // Full party set is the key's Qis key set.
410	  std::vector<std::string_view> all_party_names;
411	  all_party_names.reserve(ac_key.Qis.size());
412	  for (const auto& kv : ac_key.Qis) all_party_names.emplace_back(kv.first);
