415	  coinbase::mpc::party_set_t _unused;
416	  rv = coinbase::api::detail::to_internal_party_set(all_party_names, job.party_names, _unused);
417	  if (rv) return rv;
418	
419	  // Convert access structure to internal and validate it matches the key party set.
420	  coinbase::crypto::ss::ac_owned_t ac;
421	  rv = coinbase::api::detail::to_internal_access_structure(access_structure, all_party_names, ac_key.curve, ac);
422	  if (rv) return rv;
