459	error_t get_public_key_compressed(mem_t key_blob, buf_t& pub_key) {
460	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(key_blob, "key_blob",
461	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
462	    return rv;
463	  key_blob_v1_t blob;
464	  error_t rv = coinbase::convert(blob, key_blob);
465	  if (rv) return rv;
466	  if (blob.version != key_blob_version_v1 && blob.version != ac_key_blob_version_v1)
467	    return coinbase::error(E_FORMAT, "unsupported key blob version");
468	
469	  const auto cid = static_cast<curve_id>(blob.curve);
470	  if (cid == curve_id::ed25519) return coinbase::error(E_FORMAT, "invalid key blob curve");
471	  const auto curve = to_internal_curve(cid);
472	  if (!curve.valid()) return coinbase::error(E_FORMAT, "invalid key blob curve");
473	
474	  coinbase::crypto::ecc_point_t Q(curve);
475	  if (rv = Q.from_bin(curve, blob.Q_compressed)) return coinbase::error(rv, "invalid key blob");
476	
477	  pub_key = Q.to_compressed_bin();
478	  return SUCCESS;
479	}
